    if($matches===[]) foreach($active as $t){ if(documents_quote_import_norm_key(documents_quote_import_template_display($t))===$norm) $matches[]=$t; }
    if($matches===[]) foreach($active as $t){ if(documents_quote_import_norm_key((string)($t['name']??''))===$norm) $matches[]=$t; }
