}
function documents_quote_import_apply_template_snapshot(array $q, array $input): array {
    $res=documents_quote_import_resolve_template((string)($input['template_set']??'')); if(empty($res['ok'])) { $q['template_resolution_error']=(string)($res['error']??'Template resolution failed'); return $q; }
