}

function documents_quote_bool_from_csv($value, bool $default = true): bool { $v=strtolower(trim((string)$value)); if($v==='') return $default; return in_array($v, ['1','true','yes','y','on','enabled','enable'], true); }
function documents_quote_import_segment_codes(): array { return ['RES'=>true,'COM'=>true,'IND'=>true,'INST'=>true]; }
function documents_quote_import_normalize_input(array $input): array {
    $out=$input;
    $map=['non_dcr_kwp'=>'complimentary_non_dcr_kwp','sanctioned_load_kw'=>'sanction_load_kwp','subsidy_amount'=>'subsidy_expected_rs','transportation_amount'=>'transportation_rs','discount_amount'=>'discount_rs','phase'=>'hybrid_phase'];
    foreach($map as $from=>$to){ if(array_key_exists($from,$out) && !array_key_exists($to,$out)) $out[$to]=$out[$from]; }
    if(!array_key_exists('complimentary_non_dcr_kwp',$out)) $out['complimentary_non_dcr_kwp']='0';
    $pt=strtolower(trim((string)($out['party_type']??'lead')));
    $segHint='';
    $upper=strtoupper(trim((string)($out['party_type']??'')));
    if(isset(documents_quote_import_segment_codes()[$upper])) { $segHint=$upper; $pt='lead'; }
    $out['party_type']=in_array($pt,['customer','lead'],true)?$pt:'lead';
    if($segHint!=='' && trim((string)($out['segment']??''))==='') $out['segment']=$segHint;
    if(trim((string)($out['show_tax_breakup']??''))==='') $out['show_tax_breakup']='1';
    if(trim((string)($out['pricing_mode']??''))==='') $out['pricing_mode']='solar_split_70_30';
    if(trim((string)($out['place_of_supply_state']??''))==='') $out['place_of_supply_state']='Jharkhand';
    if(trim((string)($out['primary_finance_scenario']??''))==='') $out['primary_finance_scenario']='self_funded';
    return $out;
}
